import { useEffect, useRef } from "react";
import { useInView } from "framer-motion";

import { Button } from "@nextui-org/react";

function TableInfo({ cat, formas_data, data, showMore }) {
  const ref = useRef(null);
  const isInView = useInView(ref);

  const columns = [
    {
      key: "medida",
      label: "Medida",
      measure: "mm",
    },
    {
      key: "peso",
      label: "Peso",
      measure: "g",
    },
    {
      key: "fuerza_experimental",
      label: "F. exp.",
      measure: "kg",
    },
    {
      key: "grade",
      label: "Grado",
    },
    {
      key: "fuerza",
      label: "Fuerza",
      measure: "kg",
    },
    {
      key: "gauss",
      label: "Campo",
      measure: "gauss",
    },
  ];

  const makeCell = (row, key) => {
    const val = row[1]?.[key];

    switch (key) {
      case "medida":
        return row[0].replace("_", " ");
      case "grade":
        return row[1]?.N
          ? Object.keys(row[1]?.N).map((g, i) => <p key={i}>N{g}</p>)
          : 35;
      case "fuerza":
      case "gauss":
        return row[1]?.N
          ? Object.values(row[1]?.N).map((v, i) => (
              <div key={i}>{v?.[key]}</div>
            ))
          : "-";

      default:
        return val ? val : "-";
    }
  };

  useEffect(() => {
    if (isInView) showMore(cat);
  }, [isInView]);

  return (
    <div
      data-slot="table-container"
      className="pb-4 w-full overflow-x-auto scrollbar scrollbar-thumb-rounded-full scrollbar-track-rounded-full scrollbar-thumb-custom1 scrollbar-track-custom2-10 scrollbar-w-3 scrollbar-h-3 hover:scrollbar-thumb-custom1-6"
    >
      <table
        aria-label={`Tabla de precios: ${formas_data?.[cat]?.label}`}
        className="w-full sm:min-w-[750px] max-w-[900px] font-semibold lg:place-self-center table-dinamic max-sm:border-separate border-spacing-y-3"
      >
        <thead className="border-b-3">
          <tr>
            {columns.map((col) => (
              <td key={col?.key}>
                {col?.label}
                {col?.measure ? <div>({col?.measure})</div> : null}
              </td>
            ))}
          </tr>
        </thead>

        <tbody>
          {data?.rows?.map((row) => (
            <tr
              key={row?.[0]}
              className="even:text-custom2-10 dark:even:text-custom1 group hover:text-white text-center"
            >
              {columns.map((col) => (
                <td
                  key={`${row?.[0]}_${col?.key}`}
                  data-label={
                    col?.label + (col?.measure ? `(${col?.measure})` : "")
                  }
                  className="p-2 hover:!text-custom1-5 max-sm:first:border-y-3 max-sm:last:border-b-3 max-sm:border-x-3 last:rounded-b-lg max-sm:first:rounded-t-lg group-hover:bg-custom2"
                >
                  {makeCell(row, col?.key)}
                </td>
              ))}
            </tr>
          ))}

          <tr>
            <td colSpan={1} className="pt-4">
              {data?.rows?.length < data?.total && (
                <Button
                  ref={ref}
                  size="lg"
                  className="bg-custom1-2 text-custom2--2 font-bold text-xl hover:scale-105"
                  onPress={() => showMore(cat)}
                >
                  +Mas
                </Button>
              )}
            </td>
            <td colSpan={4}></td>
          </tr>
        </tbody>
      </table>
    </div>
  );
}

export default TableInfo;
